codeExample:
console.log('1');
setTimeout(() => console.log('2'), 0);
Promise.resolve().then(() => console.log('3'));
console.log('4');
// Output: 1, 4, 3, 2
// Reason: sync first, then microtasks (Promise), then macrotasks (setTimeout)

function makeCounter() {
  let count = 0;
  return () => ++count;
}
const counter = makeCounter();
console.log(counter()); // 1
console.log(counter()); // 2
// count is captured in the closure — not re-initialized each call

const animal = { breathes: true };
const dog = Object.create(animal);
dog.barks = true;

console.log(dog.barks);   // true  (own property)
console.log(dog.breathes); // true  (found on prototype)
console.log(dog.hasOwnProperty('breathes')); // false

const p1 = Promise.resolve(1);
const p2 = Promise.reject('err');
const p3 = Promise.resolve(3);

Promise.allSettled([p1, p2, p3]).then(results =>
  results.forEach(r => console.log(r.status, r.value ?? r.reason))
);
// fulfilled 1
// rejected  err
// fulfilled 3

const obj = {
  name: 'obj',
  regular() { return this.name; },    // 'obj'
  arrow: () => this?.name,             // undefined (lexical this)
};

const fn = obj.regular;
fn(); // undefined (lost binding)
fn.call(obj); // 'obj' (explicit binding)

function* range(start, end) {
  for (let i = start; i <= end; i++) yield i;
}

for (const n of range(1, 5)) console.log(n); // 1 2 3 4 5
